example_output:
# Register:
POST /api/auth/register {"username":"aisha","password":"Secure123!","email":"aisha@example.com"}
→ 201 {"userId":"U-001","username":"aisha","token":"eyJ..."}

# Login:
POST /api/auth/login {"username":"aisha","password":"Secure123!"}
→ 200 {"token":"eyJ...","username":"aisha","roles":["ROLE_USER"]}

# Create payment (with token):
POST /api/payments
Authorization: Bearer eyJ...
{"amount":1500,"currency":"INR","orderId":"ORD-001"}
→ 201 {"id":"PAY-001","status":"CREATED",...}

# Create payment (no token):
POST /api/payments
→ 401 Unauthorized

# Refund as USER:
POST /api/payments/PAY-001/refund
Authorization: Bearer [aisha-token]
→ 403 Forbidden

# Refund as ADMIN:
POST /api/payments/PAY-001/refund
Authorization: Bearer [admin-token]
→ 200 {"status":"REFUNDED"}
